import logging
from logging.handlers import TimedRotatingFileHandler

# Configure log storage location and implement log rotation
log_file_path = '/var/log/myapp.log'
log_handler = TimedRotatingFileHandler(log_file_path, when='midnight', interval=1, backupCount=7)
log_formatter = logging.Formatter('%(asctime)s - %(name)s - %(levelname)s - %(message)s')
log_handler.setFormatter(log_formatter)

# Set file permissions for log files
import os
os.chmod(log_file_path, 0o640)  # Read and write for owner, read for group and others

# Create logger
logger = logging.getLogger('myapp')
logger.setLevel(logging.DEBUG)
logger.addHandler(log_handler)

# Example usage of the logger
logger.info('This is an info message')
logger.error('This is an error message')